import os, pty, subprocess, time, tempfile, signal, select, shutil

tmpdir = tempfile.mkdtemp(prefix='zmux-smoke-')
env = os.environ.copy()
env['ZMUX_TMPDIR'] = tmpdir
env['TERM'] = env.get('TERM', 'xterm-256color')
master, slave = pty.openpty()
proc = subprocess.Popen(
    ['./zig-out/bin/zmux', 'new-session', '-s', 'demo'],
    cwd='.', stdin=slave, stdout=slave, stderr=slave,
    env=env, preexec_fn=os.setsid, close_fds=True,
)
os.close(slave)
out = bytearray()
attached = False
start = time.time()
try:
    deadline = time.time() + 6.0
    while time.time() < deadline and proc.poll() is None:
        r, _, _ = select.select([master], [], [], 0.2)
        if not r:
            continue
        try:
            chunk = os.read(master, 4096)
        except OSError:
            break
        if not chunk:
            break
        out.extend(chunk)
        text = out.decode('utf-8', 'replace')
        if 'demo' in text and '❯' in text:
            attached = True
            break
finally:
    try:
        os.killpg(proc.pid, signal.SIGTERM)
    except ProcessLookupError:
        pass
    try:
        proc.wait(timeout=3)
    except Exception:
        try:
            os.killpg(proc.pid, signal.SIGKILL)
        except ProcessLookupError:
            pass
        try:
            proc.wait(timeout=3)
        except Exception:
            pass
    os.close(master)
    shutil.rmtree(tmpdir, ignore_errors=True)

print(f'attached={attached}')
print(f'returncode={proc.returncode}')
print(f'elapsed_ms={int((time.time()-start)*1000)}')
