import os, pty, subprocess, tempfile, time, select, signal, shutil, statistics
from pathlib import Path

def kill_descendants(root_pid):
    try:
        ps = subprocess.check_output(['ps', '-axo', 'pid,ppid,command'], text=True)
    except Exception:
        return
    parent_to_children = {}
    for line in ps.splitlines():
