        seen.add(cur); order.append(cur); stack.extend(parent_to_children.get(cur, []))
    for pid in reversed(order):
        try: os.kill(pid, signal.SIGTERM)
        except Exception: pass
    time.sleep(0.2)
    for pid in reversed(order):
        try: os.kill(pid, signal.SIGKILL)
        except Exception: pass

