        os.close(slave)
        start = time.time()
        time.sleep(0.05)
        os.write(master, f'touch {proof}\r'.encode())
        success = False
        while time.time() - start < 8.0:
            if proof.exists():
                success = True
                break
            r, _, _ = select.select([master], [], [], 0.1)
            if r:
                try:
                    chunk = os.read(master, 4096)
                except OSError:
                    break
                if not chunk:
                    break
            if launcher.poll() is not None:
                break
        elapsed = round(time.time() - start, 3)
        results.append({'run': run, 'success': success, 'elapsed_s': elapsed})
    finally:
        if launcher is not None:
            kill_descendants(launcher.pid)
            try: launcher.wait(timeout=1)
            except Exception: pass
        if master is not None:
            try: os.close(master)
            except Exception: pass
        shutil.rmtree(tmpdir, ignore_errors=True)
        try:
            if proof.exists(): proof.unlink()
        except Exception:
            pass

successes = [r['elapsed_s'] for r in results if r['success']]
print(results)
print('success_count=', len(successes))
if successes:
    print('mean_success_s=', round(statistics.mean(successes), 3))
    print('max_success_s=', round(max(successes), 3))
